examples.code:
for (int i = 1; i <= 5; i++) {
    System.out.println("Count: " + i);
}

int num = 1234;
int sum = 0;
while (num > 0) {
    sum += num % 10;
    num /= 10;
}
System.out.println("Sum: " + sum);

int[][] matrix = {
    {1, 2, 3},
    {4, 5, 6}
};
for (int[] row : matrix) {
    for (int value : row) {
        System.out.print(value + " ");
    }
    System.out.println();
}

