coding_challenges.solution:
int n = 8;
int first = 0, second = 1;
System.out.print(first);
if (n > 1) {
    System.out.print(", " + second);
}
for (int i = 3; i <= n; i++) {
    int next = first + second;
    System.out.print(", " + next);
    first = second;
    second = next;
}
